// Generated by AI (UnitTest MCP)
//! Persistence for design items (ADR-0023): register, read, and the guarded
//! accept/reject state transition. Like the claim CAS, the decision is a single
//! guarded statement so concurrent deciders cannot both win.

use rusqlite::{params, Row, Transaction, TransactionBehavior};

use crate::design::{
    design_id_from_path, DesignItem, DesignMaterializationMode, DesignMaterializationPlan,
    DesignMaterializationRecord, DesignMetadata, DesignPromotion, DesignPromotionStatus,
    DesignStatus,
};
use crate::error::{LodestarError, Result};
use crate::model::{Goal, Task};

use super::{
    collect, coordination,
    design_materialization::{ensure_objective, validate_materialization_plan},
    goals, LodestarStore,
};

const DESIGN_COLS: &str =
    "id, adr_path, title, summary, status, proposed_by, decided_by, reason, created_at, updated_at, promotion_status, materialization_revision";

impl LodestarStore {
    /// Reconcile structured repository ADR metadata into the durable design
    /// ledger. Existing rows always win: repository discovery must never
    /// overwrite a Design Board decision or re-arm promotion.
    pub fn reconcile_design_item(&self, metadata: &DesignMetadata, now: i64) -> Result<DesignItem> {
        let id = design_id_from_path(&metadata.adr_path);
        self.conn.execute(
            "INSERT OR IGNORE INTO design_items
                (id, adr_path, title, summary, status, proposed_by, decided_by,
                 reason, created_at, updated_at, promotion_status, materialization_revision)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, NULL, NULL, ?7, ?7,
                     'not_required', 0)",
            params![
                id,
                metadata.adr_path,
                metadata.title,
                metadata.summary,
                metadata.status.as_str(),
                metadata.proposed_by,
                now
            ],
        )?;
        self.get_design_item(&id)?
            .ok_or_else(|| LodestarError::NotFound(id))
    }

    /// Register a new proposed design item. Fails if the ADR is already
    /// registered (its id is derived from the ADR path, so this is idempotent
    /// per ADR).
    pub fn register_design_item(
        &self,
        id: &str,
        adr_path: &str,
        title: &str,
        summary: &str,
        proposed_by: Option<&str>,
        now: i64,
    ) -> Result<DesignItem> {
        if self.get_design_item(id)?.is_some() {
            return Err(LodestarError::Invalid(format!(
                "design item already registered: {id}"
            )));
        }
        self.conn.execute(
            "INSERT INTO design_items
                (id, adr_path, title, summary, status, proposed_by, decided_by, reason, created_at, updated_at)
             VALUES (?1, ?2, ?3, ?4, 'proposed', ?5, NULL, NULL, ?6, ?6)",
            params![id, adr_path, title, summary, proposed_by, now],
        )?;
        self.get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))
    }

    pub fn get_design_item(&self, id: &str) -> Result<Option<DesignItem>> {
        let sql = format!("SELECT {DESIGN_COLS} FROM design_items WHERE id = ?1");
        let mut stmt = self.conn.prepare(&sql)?;
        let mut rows = stmt.query(params![id])?;
        match rows.next()? {
            Some(row) => Ok(Some(row_to_design(row)?)),
            None => Ok(None),
        }
    }

    /// List design items, oldest first. `status = None` returns every item
    /// (durable audit view); `Some(Proposed)` is the Design Board.
    pub fn list_design_items(&self, status: Option<DesignStatus>) -> Result<Vec<DesignItem>> {
        match status {
            Some(status) => {
                let sql = format!(
                    "SELECT {DESIGN_COLS} FROM design_items WHERE status = ?1 \
                     ORDER BY created_at ASC, id ASC"
                );
                let mut stmt = self.conn.prepare(&sql)?;
                let rows = stmt.query_map(params![status.as_str()], row_to_design)?;
                collect(rows)
            }
            None => {
                let sql = format!(
                    "SELECT {DESIGN_COLS} FROM design_items ORDER BY created_at ASC, id ASC"
                );
                let mut stmt = self.conn.prepare(&sql)?;
                let rows = stmt.query_map([], row_to_design)?;
                collect(rows)
            }
        }
    }

    /// Human-actionable Design Board rows: proposed decisions plus accepted
    /// designs whose implementation promotion is pending or retryable.
    pub fn actionable_design_items(&self) -> Result<Vec<DesignItem>> {
        let sql = format!(
            "SELECT {DESIGN_COLS} FROM design_items
             WHERE status = 'proposed'
                OR (status = 'accepted' AND promotion_status = 'pending')
             ORDER BY created_at ASC, id ASC"
        );
        let mut stmt = self.conn.prepare(&sql)?;
        let rows = stmt.query_map([], row_to_design)?;
        collect(rows)
    }

    /// Resolve the durable objective/task/constraint provenance for a
    /// materialized design. Proposed and pending designs have no materialized
    /// plan yet and return `None`; this read never invokes planning.
    pub fn design_promotion(&self, id: &str) -> Result<Option<DesignPromotion>> {
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        if item.promotion_status != DesignPromotionStatus::Materialized {
            return Ok(None);
        }
        self.resolve_promotion(&item).map(Some)
    }

    /// Append-only reviewed materialization decisions, oldest first.
    pub fn design_materialization_history(
        &self,
        id: &str,
    ) -> Result<Vec<DesignMaterializationRecord>> {
        if self.get_design_item(id)?.is_none() {
            return Err(LodestarError::NotFound(id.to_string()));
        }
        let mut statement = self.conn.prepare(
            "SELECT design_id, revision, plan_json, actor, created_at
             FROM design_materializations WHERE design_id = ?1 ORDER BY revision ASC",
        )?;
        let rows = statement.query_map(params![id], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, i64>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, String>(3)?,
                row.get::<_, i64>(4)?,
            ))
        })?;
        let mut records = Vec::new();
        for row in rows {
            let (design_id, revision, plan_json, actor, created_at) = row?;
            let plan = serde_json::from_str(&plan_json).map_err(|error| {
                LodestarError::Invalid(format!(
                    "design materialization {design_id} revision {revision} has invalid JSON: {error}"
                ))
            })?;
            records.push(DesignMaterializationRecord {
                design_id,
                revision,
                plan,
                actor,
                created_at,
            });
        }
        Ok(records)
    }

    /// Guarded CAS: move a *proposed* item to accepted/rejected. Returns `false`
    /// when the item is not currently proposed (missing or already decided), so
    /// a concurrent second decider cannot overwrite the first.
    pub fn decide_design_item(
        &self,
        id: &str,
        target: DesignStatus,
        decided_by: &str,
        reason: Option<&str>,
        now: i64,
    ) -> Result<bool> {
        // Accepting arms promotion (pending); any other decision leaves it off.
        let promotion = if target == DesignStatus::Accepted {
            DesignPromotionStatus::Pending
        } else {
            DesignPromotionStatus::NotRequired
        };
        let changed = self.conn.execute(
            "UPDATE design_items SET status = ?2, decided_by = ?3, reason = ?4, promotion_status = ?5, updated_at = ?6
             WHERE id = ?1 AND status = 'proposed'",
            params![id, target.as_str(), decided_by, reason, promotion.as_str(), now],
        )?;
        Ok(changed == 1)
    }

    /// Atomically materialize an explicit reviewed plan. A repair appends a new
    /// revision and replaces only the current link projection; prior plans and
    /// tasks remain durable.
    pub fn materialize_design_item(
        &self,
        id: &str,
        plan: &DesignMaterializationPlan,
        actor: &str,
        repair: bool,
        now: i64,
    ) -> Result<DesignPromotion> {
        validate_materialization_plan(plan)?;
        let actor = actor.trim();
        if actor.is_empty() {
            return Err(LodestarError::Invalid(
                "a human materialization reviewer is required".to_string(),
            ));
        }
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        if item.status != DesignStatus::Accepted {
            return Err(LodestarError::Invalid(format!(
                "design item {id} is {}; only an accepted design can be materialized",
                item.status.as_str()
            )));
        }
        let previous = self.design_materialization_history(id)?.pop();
        if previous.as_ref().is_some_and(|record| record.plan == *plan) {
            return self.resolve_promotion(&item);
        }
        if repair {
            if item.promotion_status != DesignPromotionStatus::Materialized {
                return Err(LodestarError::Invalid(format!(
                    "design item {id} has no materialization to repair"
                )));
            }
            if plan
                .rationale
                .as_deref()
                .is_none_or(|value| value.trim().is_empty())
            {
                return Err(LodestarError::Invalid(
                    "a repair rationale is required".to_string(),
                ));
            }
        } else if item.promotion_status != DesignPromotionStatus::Pending {
            return Err(LodestarError::Invalid(format!(
                "design item {id} is already materialized; use revise_design_promotion with a rationale"
            )));
        }

        let revision = item.materialization_revision + 1;
        let transaction = Transaction::new_unchecked(&self.conn, TransactionBehavior::Immediate)?;
        let won = if repair {
            transaction.execute(
                "UPDATE design_items
                 SET materialization_revision = ?2, updated_at = ?3
                 WHERE id = ?1 AND status = 'accepted' AND promotion_status = 'materialized'
                   AND materialization_revision = ?4",
                params![id, revision, now, item.materialization_revision],
            )?
        } else {
            transaction.execute(
                "UPDATE design_items
                 SET promotion_status = 'materialized', materialization_revision = ?2, updated_at = ?3
                 WHERE id = ?1 AND status = 'accepted' AND promotion_status = 'pending'
                   AND materialization_revision = ?4",
                params![id, revision, now, item.materialization_revision],
            )?
        };
        if won != 1 {
            return Err(LodestarError::Invalid(format!(
                "design item {id} materialization changed concurrently"
            )));
        }
        let plan_json = serde_json::to_string(plan).map_err(|error| {
            LodestarError::Invalid(format!("could not serialize materialization plan: {error}"))
        })?;
        transaction.execute(
            "INSERT INTO design_materializations
                 (design_id, revision, mode, plan_json, rationale, actor, created_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
            params![
                id,
                revision,
                plan.mode.as_str(),
                plan_json,
                plan.rationale.as_deref().map(str::trim),
                actor,
                now
            ],
        )?;
        transaction.execute(
            "DELETE FROM design_task_links WHERE design_id = ?1",
            params![id],
        )?;
        transaction.execute(
            "DELETE FROM design_goal_links WHERE design_id = ?1 AND role = 'objective'",
            params![id],
        )?;

        let mut tasks = Vec::new();
        match plan.mode {
            DesignMaterializationMode::Create => {
                for draft in &plan.tasks {
                    tasks.push(coordination::create_task_on(
                        &transaction,
                        &draft.goal_id,
                        &draft.title,
                        &draft.acceptance,
                        now,
                    )?);
                }
            }
            DesignMaterializationMode::Link => {
                for task_id in &plan.task_ids {
                    tasks.push(
                        coordination::get_task_on(&transaction, task_id)?
                            .ok_or_else(|| LodestarError::NotFound(task_id.clone()))?,
                    );
                }
            }
            DesignMaterializationMode::NoWork => {}
        }

        let mut objective_ids = Vec::new();
        for (position, task) in tasks.iter().enumerate() {
            ensure_objective(&transaction, &task.goal_id)?;
            transaction.execute(
                "INSERT INTO design_task_links (design_id, task_id, position)
                 VALUES (?1, ?2, ?3)",
                params![id, task.id, position as i64],
            )?;
            if !objective_ids.contains(&task.goal_id) {
                objective_ids.push(task.goal_id.clone());
            }
        }
        for (position, goal_id) in objective_ids.iter().enumerate() {
            transaction.execute(
                "INSERT INTO design_goal_links (design_id, goal_id, role, position)
                 VALUES (?1, ?2, 'objective', ?3)",
                params![id, goal_id, position as i64],
            )?;
        }
        let constraint_offset: i64 = transaction.query_row(
            "SELECT COALESCE(MAX(position) + 1, 0) FROM design_goal_links
             WHERE design_id = ?1 AND role <> 'objective'",
            params![id],
            |row| row.get(0),
        )?;
        for (position, draft) in plan.constraints.iter().enumerate() {
            let constraint = goals::define_goal_on(
                &transaction,
                draft.kind,
                &draft.title,
                &draft.statement,
                None,
                now,
            )?;
            transaction.execute(
                "INSERT INTO design_goal_links (design_id, goal_id, role, position)
                 VALUES (?1, ?2, ?3, ?4)",
                params![
                    id,
                    constraint.id,
                    draft.kind.as_str(),
                    constraint_offset + position as i64
                ],
            )?;
        }
        transaction.commit()?;
        let item = self
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.into()))?;
        self.resolve_promotion(&item)
    }

    /// Reconstruct a materialised promotion from its durable provenance links so
    /// a retry returns the same plan without re-running planning.
    fn resolve_promotion(&self, item: &DesignItem) -> Result<DesignPromotion> {
        let record = self
            .design_materialization_history(&item.id)?
            .pop()
            .ok_or_else(|| {
                LodestarError::Invalid(format!(
                    "design item {} is materialized without an audit record",
                    item.id
                ))
            })?;
        let tasks = self.linked_tasks(&item.id)?;
        let goals = self.linked_objective_goals(&item.id)?;
        let constraints = self.linked_constraint_goals(&item.id)?;
        Ok(DesignPromotion {
            item: item.clone(),
            mode: record.plan.mode,
            revision: record.revision,
            rationale: record.plan.rationale,
            goals,
            tasks,
            constraints,
        })
    }

    fn linked_tasks(&self, design_id: &str) -> Result<Vec<Task>> {
        let ids: Vec<String> = {
            let mut stmt = self.conn.prepare(
                "SELECT task_id FROM design_task_links WHERE design_id = ?1 ORDER BY position ASC",
            )?;
            let rows = stmt.query_map(params![design_id], |row| row.get::<_, String>(0))?;
            collect(rows)?
        };
        let mut tasks = Vec::with_capacity(ids.len());
        for id in ids {
            if let Some(task) = self.get_task(&id)? {
                tasks.push(task);
            }
        }
        Ok(tasks)
    }

    fn linked_constraint_goals(&self, design_id: &str) -> Result<Vec<Goal>> {
        let ids: Vec<String> = {
            let mut stmt = self.conn.prepare(
                "SELECT goal_id FROM design_goal_links
                 WHERE design_id = ?1 AND role <> 'objective' ORDER BY position ASC",
            )?;
            let rows = stmt.query_map(params![design_id], |row| row.get::<_, String>(0))?;
            collect(rows)?
        };
        let mut goals = Vec::with_capacity(ids.len());
        for id in ids {
            if let Some(goal) = self.get_goal(&id)? {
                goals.push(goal);
            }
        }
        Ok(goals)
    }

    fn linked_objective_goals(&self, design_id: &str) -> Result<Vec<Goal>> {
        let ids: Vec<String> = {
            let mut stmt = self.conn.prepare(
                "SELECT goal_id FROM design_goal_links
                 WHERE design_id = ?1 AND role = 'objective' ORDER BY position ASC",
            )?;
            let rows = stmt.query_map(params![design_id], |row| row.get::<_, String>(0))?;
            collect(rows)?
        };
        let mut goals = Vec::with_capacity(ids.len());
        for id in ids {
            if let Some(goal) = self.get_goal(&id)? {
                goals.push(goal);
            }
        }
        Ok(goals)
    }
}

fn row_to_design(row: &Row) -> rusqlite::Result<DesignItem> {
    Ok(DesignItem {
        id: row.get(0)?,
        adr_path: row.get(1)?,
        title: row.get(2)?,
        summary: row.get(3)?,
        status: DesignStatus::from_tag(&row.get::<_, String>(4)?).unwrap_or(DesignStatus::Proposed),
        proposed_by: row.get(5)?,
        decided_by: row.get(6)?,
        reason: row.get(7)?,
        created_at: row.get(8)?,
        updated_at: row.get(9)?,
        promotion_status: DesignPromotionStatus::from_tag(&row.get::<_, String>(10)?)
            .unwrap_or(DesignPromotionStatus::NotRequired),
        materialization_revision: row.get(11)?,
    })
}
